import { useEffect, useState } from "react";
import {
  addDoc,
  collection,
  onSnapshot,
  orderBy,
  query,
  serverTimestamp
} from "firebase/firestore";
import { db } from "../firebase";
import { useAuth } from "../context/AuthContext";

const fallbackActionTypes = [
  { id: "clearance", label: "Clearance", value: "clearance" },
  { id: "refund", label: "Refund", value: "refund" },
  { id: "bells", label: "Bells", value: "bells" }
];

export default function ActionSelector() {
  const { currentUser } = useAuth();
  const [actionTypes, setActionTypes] = useState(fallbackActionTypes);
  const [message, setMessage] = useState("");

  useEffect(() => {
    const actionTypesQuery = query(collection(db, "action_types"), orderBy("label", "asc"));

    const unsubscribe = onSnapshot(actionTypesQuery, (snapshot) => {
      const liveActionTypes = snapshot.docs.map((actionTypeDoc) => {
        const data = actionTypeDoc.data();

        return {
          id: actionTypeDoc.id,
          label: data.label || data.name || actionTypeDoc.id,
          value: data.value || data.actionType || actionTypeDoc.id
        };
      });

      if (liveActionTypes.length > 0) {
        setActionTypes(liveActionTypes);
      }
    });

    return unsubscribe;
  }, []);

  const handleLogAction = async (actionType) => {
    if (!currentUser) return;

    await addDoc(collection(db, "agent_actions"), {
      agentId: currentUser.uid,
      agentName: currentUser.displayName || currentUser.email || "Unknown Agent",
      actionType,
      timestamp: serverTimestamp()
    });

    const label = actionTypes.find((item) => item.value === actionType)?.label || actionType;
    setMessage(`Logged: ${label}`);
    window.setTimeout(() => setMessage(""), 2200);
  };

  return (
    <section className="bg-white p-6 rounded-lg shadow-sm border border-gray-100 mb-8">
      <div className="flex items-center justify-between gap-4 mb-4">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Quick Actions</h2>
          <p className="text-sm text-gray-500 mt-1">Log the action you are taking on this call.</p>
        </div>
        {message && (
          <span className="text-sm font-bold text-green-700 bg-green-50 border border-green-100 px-3 py-1.5 rounded-full">
            {message}
          </span>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
        {actionTypes.map((actionType) => (
          <button
            key={actionType.id}
            type="button"
            onClick={() => handleLogAction(actionType.value)}
            className="min-h-[82px] rounded-lg border border-gray-200 bg-gray-50 hover:bg-white hover:border-blue-300 hover:shadow-sm transition-all text-left p-4"
          >
            <span className="block text-base font-extrabold text-gray-800">{actionType.label}</span>
            <span className="block text-xs font-semibold text-gray-500 mt-1">Log action</span>
          </button>
        ))}
      </div>
    </section>
  );
}
